"""
MKT Context Layer — Ezekiel chapters 26–28
Run: python3 scripts/zc-context-ezekiel-26-28-fill.py

Historical-cultural contexts:

Ch 26: First oracle against Tyre (judgment). Date: 587 BCE, immediately after
  or during Jerusalem's fall. Tyre's rejoicing that Jerusalem's fall opens land
  trade routes — the commercial-political motivation. Nebuchadnezzar explicitly
  named as instrument. Tyre = Hebrew ṣûr (rock) — the scraping-bare plays on
  the name. 13-year mainland siege (585-572 BCE); Alexander's 332 BCE causeway
  construction from demolished ruins fulfilled the bare-rock/never-rebuilt oracle.

Ch 27: Extended ship-of-state allegory — the most detailed commercial geography
  in the ancient world: 16 named trade partners covering Spain to Arabia. Key
  nodes: Tarshish (Spain/Sardinia — tin, silver, lead), Beth-Togarmah (horses
  from Armenia), Judah (wheat, honey, oil, balm), Sheba/Raamah (spices and gold),
  Damascus (wine of Helbon). The Tyrian ship wrecked by the east wind (Babylonian
  power); universal maritime mourning.

Ch 28: Two oracles — prince vs king of Tyre. Prince (nasi) = Ithobaal III
  (c.591-573 BCE), who claimed divine status ("I am a god; I sit in the seat of
  gods"). King oracle: cosmic-Eden imagery — in the divine garden, adorned with
  precious stones, the anointed guardian cherub, walking among fiery stones —
  beauty and perfection until violence found within; expelled from the divine
  mountain. Ch 28 closes with the oracle against Sidon and Israel's restoration
  promise: the last oracles before the Egypt section begins (chs 29-32).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZK_CTX = {
  "26": {
    "1": "<p>Date: eleventh year, first day of the month (month unstated). The missing month may indicate a scribal gap or may mean the oracle arrived at a moment when the specific month was less important than the year. Eleventh year of Jehoiachin's exile = 587/586 BCE — the year Jerusalem fell to Nebuchadnezzar. The proximity to Jerusalem's fall is the oracle's immediate context: Tyre's response to news of Jerusalem's destruction is the trigger.</p>",
    "2": "<p>'Tyre has said against Jerusalem, Aha! The gate of the peoples is broken; it has swung open to me; I will be replenished, now that she is laid waste' — Jerusalem as the land-trade gateway. The ancient Via Maris and King's Highway, the two major trade arteries linking Egypt with Mesopotamia and Arabia, both passed through or near Judah. Jerusalem's customs and market monopoly on land-trade was a commercial rival to Tyre's maritime dominance. Tyre's commercial calculation: with Jerusalem's destruction, the land-route trade that formerly enriched Jerusalem would now flow through Tyre's markets. The oracle indicts this predatory commercial opportunism over a fallen covenant people.</p>",
    "3": "<p>'I am against you, Tyre, and I will bring many nations against you as the sea brings up its waves' — the sea metaphor is particularly apt for Tyre, whose maritime power made it the master of the sea. YHWH uses Tyre's own element — the sea and its waves — as the image of the judgment. The 'many nations' (vs. the single instrument of Nebuchadnezzar in v.7) may reflect the reality that multiple Babylonian campaigns plus Alexander's eventual conquest constituted the fulfillment.</p>",
    "4": "<p>'They will destroy the walls of Tyre and tear down her towers; I will also scrape the soil from her and make her a bare rock' — the name 'Tyre' (Hebrew <em>ṣôr</em>, Phoenician <em>ṣûr</em>) means 'rock.' The city was partly on the mainland and partly on a small island 800 meters offshore. The prediction of a 'bare rock' (<em>sela</em>) literally describes what the island city would become: Alexander the Great (332 BCE), frustrated by his inability to assault the island by sea, demolished the ruins of the mainland city and built a causeway from the debris to the island. This required stripping the mainland ruins down to bedrock — fulfilling the 'bare rock' oracle in a historically precise way 250 years later.</p>",
    "5": "<p>'She will become a place in the middle of the sea for the spreading of nets' — the drying of fishing nets on Tyre's bare rock is attested by ancient geographers after Alexander's conquest. The 'for I have spoken' (<em>ki ani dibbarthu</em>) grounds the prediction in YHWH's word: the authority is the divine speech-act, not historical probability. Tyre was one of the most heavily fortified city-states of the ancient world; its fall was historically improbable at the time of Ezekiel's oracle.</p>",
    "6": "<p>'Her daughters on the mainland will be slain by the sword' — the 'daughters' are the satellite towns on the mainland coast (Ushu, the mainland settlement of Tyre, plus dependent villages). Nebuchadnezzar's 13-year siege (585-572 BCE) successfully destroyed the mainland settlements even if the island city was never fully taken. The mainland daughters/villages were the most vulnerable; the island fortress held out.</p>",
    "7": "<p>'I am bringing against Tyre from the north Nebuchadnezzar king of Babylon, king of kings, with horses, chariots, cavalry, and a great army' — Nebuchadnezzar is explicitly named and given the title 'king of kings' (<em>melek melachim</em>), the standard Neo-Babylonian royal title reflecting Nebuchadnezzar's position as the paramount monarch of the ancient Near East (cf. Dan 2:37 where Daniel addresses him with the same title). His approach 'from the north' follows the Fertile Crescent route that all Mesopotamian armies took to reach the Levantine coast: north through Syria then south along the coast.</p>",
    "8": "<p>The standard siege-warfare vocabulary of the 6th century BCE: siege works (<em>dayeq</em>), earthen ramp (<em>solelah</em>), large shields (<em>tsinah</em>), battering rams. The siege methods Nebuchadnezzar would employ against mainland Tyre were standard Assyrian and Babylonian siege engineering. The specificity of the siege vocabulary shows Ezekiel's familiarity with contemporary military practice.</p>",
    "9": "<p>Battering rams directed against the walls, axes against the towers — the archaeological evidence from Babylonian campaigns (including Lachish reliefs from Sennacherib's earlier campaigns) shows exactly this combination: rams to breach walls at base level, axes/picks to demolish towers. The imagery is technically precise for ancient siege warfare.</p>",
    "10": "<p>'Because of his many horses their dust will cover you; your walls will shake at the noise of horsemen, wheels, and chariots' — the dust of a large cavalry force as an environmental feature of the approach. Neo-Babylonian armies were predominantly infantry but used significant cavalry and chariotry. The 'many horses' signals the scale of the force. The 'walls shaking at the noise' is both literal (vibration from marching armies) and a standard ancient Near Eastern expression for military intimidation.</p>",
    "11": "<p>'His horses' hooves will trample all your streets; he will slaughter your people with the sword and your strong pillars will fall to the ground' — the 'strong pillars' (<em>mattzevot</em>) may refer to the standing stones/pillars at Tyre's famous temple of Melqart (Tyrian Heracles). Herodotus (2.44) describes visiting the great temple of Heracles at Tyre with two columns, one of pure gold and one of emerald. The specific destruction of cultic pillars was standard Babylonian practice for subordinating foreign religious establishments.</p>",
    "12": "<p>The plural subject ('they') may shift to the later conqueror Alexander or to the general 'many nations' of v.3. 'They will plunder your wealth and loot your merchandise; they will break down your walls and destroy your fine houses and hurl your stones, your timber, and your soil into the sea' — this verse is the key to the Alexander fulfillment: the debris of the mainland city (stones, timber, soil) literally thrown into the sea to build the causeway. The verse describes both the destruction and the disposal of the rubble.</p>",
    "13": "<p>'I will put an end to the noise of your songs, and the sound of your harps will be heard no more' — Tyre's famous musical culture: the city's merchants and traders were accompanied by music (Isa 23:16: 'take a harp, go about the city, O forgotten prostitute; make sweet melody, sing many songs'). The cessation of music is the standard ancient Near Eastern sign for the end of a city's life — compare the mourning songs for fallen cities in Sumerian and Akkadian literature (the Lamentation over the Destruction of Ur).</p>",
    "14": "<p>'I will make you a bare rock; you will be a place for the spreading of nets and will never be rebuilt, for I the LORD have spoken' — the combination of the bare-rock image and the never-rebuilt prediction. The modern city of Sur/Tyre exists on the ancient island site, technically contradicting the literal 'never rebuilt' prediction. This has generated extensive discussion; interpreters note that the modern city occupies Alexander's causeway connection and the harbor areas, not the ancient island city itself, and that ancient Tyre as a cultural and commercial power was never restored to its former greatness.</p>",
    "15": "<p>The cosmic-scale reaction to Tyre's fall: 'Will not the coastlands tremble at the sound of your fall — at the cry of the wounded, at the groaning of the slain, when the sword is wielded in your midst?' The 'coastlands' (<em>iyim</em>) are the Mediterranean maritime cities and islands — the network of ports and trading cities for which Tyre was the hub and center. Tyre's fall disrupted the entire Mediterranean commercial network, producing genuine economic and political shock across the region.</p>",
    "16": "<p>'Then all the princes of the sea will descend from their thrones, remove their robes, and strip off their embroidered garments; they will clothe themselves with trembling' — the mourning protocol of ancient Near Eastern rulers: stripping royal regalia (robes, headdresses, embroidery) as a sign of grief and solidarity with the fallen. The 'princes of the sea' are the rulers of Phoenician, Greek, and other maritime city-states who had built their commercial systems around Tyre's network. Their mourning is both genuine grief and self-interested terror: if Tyre fell, they were vulnerable.</p>",
    "17": "<p>The lament (<em>qinah</em>): 'How you are destroyed, you who were inhabited by seafaring men, the renowned city, who was mighty on the sea!' — the qinah meter for a city is unusual; the closest parallel is the lamentations over fallen cities in Mesopotamian literature. The description 'renowned city' translates <em>ir hallulah</em>, possibly 'city of renown/praise' — Tyre's reputation throughout the ancient world was based on its commercial and nautical supremacy. The maritime peoples' existential dependence on Tyre is their grief.</p>",
    "18": "<p>'Now the coastlands tremble on the day of your fall; the islands in the sea are dismayed at your end' — the existential trembling of the maritime world at Tyre's destruction. The commercial network of the Mediterranean and Near Eastern seas was organized around Tyrian weights, measures, trade agreements, and market institutions. Their dismay is rational: the fall of the organizing center of international commerce was an economic catastrophe for all dependent parties.</p>",
    "19": "<p>'When I make you a desolate city like cities that are not inhabited, when I bring up the deep over you and the great waters cover you' — the cosmic waters covering Tyre: the island city returning to the sea from which it rose. The imagery combines the literal (the island in the sea) with the cosmic (the primordial waters of chaos, <em>tehom</em>). A prosperous island city disappearing beneath the sea is both a physical possibility (ancient harbors have subsided; parts of ancient Tyre's harbors are now underwater) and a cosmic metaphor.</p>",
    "20": "<p>'I will bring you down with those who descend to the Pit, to the ancient peoples, and I will place you in the depths of the earth, in places desolate from of old' — the Sheol imagery: Tyre joining the ancient peoples/nations (<em>am olam</em>) who have already descended to the Pit. The 'ancient peoples' in the realm of the dead parallels the Sheol roll-call of ch 32 (Egypt, Assyria, Elam in the underworld). Tyre's commercial greatness does not exempt it from the common fate of fallen empires. 'So that you will not be inhabited or shine forth in the land of the living' — the absence from the land of the living is the definition of Sheol.</p>",
    "21": "<p>'I will make you an object of terror, and you will be no more. Though you are sought, you will never be found again, declares the Lord GOD' — the final disappearance: Tyre as an object of terror (<em>billahot</em>, H1091, terrors/sudden terrors) but ultimately absent. The 'never found again' is the strongest form of the judgment: the city that was the center of the known world's commercial network becomes unfindable. The commercial and cultural legacy of ancient Tyre effectively disappears after Alexander's conquest; the Phoenician culture and its seafaring traditions do not survive the Hellenistic period as a distinct civilization.</p>"
  },
  "27": {
    "1": "<p>The word-event formula introduces the extended ship-allegory — one of the most elaborate extended metaphors in the prophetic literature. Ch 27 is simultaneously a dirge (<em>qinah</em>) and a geographical-commercial catalog, providing the most detailed single description of ancient Near Eastern trade networks outside of administrative cuneiform records.</p>",
    "2": "<p>'Raise a lamentation over Tyre' — the <em>qinah</em> form: the 3:2 meter of Hebrew funeral poetry applied to a city. This is one of three formal lamentations over Tyre in chs 26-28 (26:17-18 being the first, 28:12-19 the third). The cumulative effect of multiple lamentations over the same city is unusual and reflects the extraordinary prominence of Tyre in the ancient world — no other non-Israelite city receives this degree of sustained elegiac attention.</p>",
    "3": "<p>'You who are situated at the gateway of the sea, merchant to many coastlands' — Tyre's geographical identity: at the interface of the eastern Mediterranean and the land routes of the Levant. The term 'gateway of the sea' (<em>pethach hayammim</em>) captures Tyre's commercial position: the sea routes from the west (Spain, North Africa, Greece, Cyprus) met the land routes from the east (Mesopotamia, Arabia, Egypt) at Tyre. 'Perfect in beauty' (<em>kalil yophyi</em>) — the aesthetic dimension of Tyre's self-understanding, which the king-oracle of ch 28 will then subvert.</p>",
    "4": "<p>'Your builders have perfected your beauty' — the urban construction of Tyre as an aesthetic achievement. The island city required constant engineering: sea walls, harbor constructions, bridges to cisterns and water sources on the mainland, elaborate building projects within the cramped island space. Tyrian craftsmen were famous throughout the ancient Near East: they built Solomon's temple (1 Kgs 5-7) and provided artisans for numerous royal projects.</p>",
    "5": "<p>'They made all your planks of fir trees from Senir' — Senir (H8149) is one of the names for Mount Hermon (cf. Deut 3:9: the Amorites called it Senir while the Sidonians called it Sirion). The fir trees (<em>beroshim</em>) from the Anti-Lebanon range were prized for shipbuilding — straight-grained, lightweight, and resistant to water. The cedars of Lebanon for the mast: cedar was the premier prestige timber of the ancient Near East, used for the finest construction. Tyre had direct access to the best shipbuilding timber in the world through its position at the foot of the Lebanon range.</p>",
    "6": "<p>'Oaks of Bashan' for oars — the hard oak of the Bashan plateau (Golan Heights and northern Transjordan) was preferred for oars due to its strength and flexibility. 'Cypress wood inlaid with ivory from the coastlands of Cyprus' for the deck — Cyprus (Kittim) was both a source of copper and of fine cedar/cypress wood; its ivory came through trade with Syria and Egypt. The combination of multiple luxury materials in the deck construction reflects the extravagant craftsmanship associated with Phoenician woodwork.</p>",
    "7": "<p>'Fine embroidered linen from Egypt' for the sail — Egyptian linen was the finest in the ancient world; the Amarna letters and Egyptian papyri document Phoenician purchases of Egyptian textiles. 'Blue and purple from the coastlands of Elishah' (Alashiya = Cyprus) for the awning/flag — purple dye (<em>argaman</em>) was Tyre's most famous product. Tyrian purple (from Murex marine snails) was the most expensive dye in antiquity; only royalty and the highest nobility could afford purple-dyed textiles. The purple-fishing industry and dyeing installations have been archaeologically confirmed in the Tyre area.</p>",
    "8": "<p>'The inhabitants of Sidon and Arvad were your oarsmen' — Sidon (Tyre's sister/senior city, 40 km north) and Arvad (an island city at the northern end of the Phoenician coast, modern Arwad). The Phoenician cities supplied each other's labor needs and crew bases. 'Your own skilled men, O Tyre, served as your pilots' — the Tyrians themselves as navigators and captains of their own fleet, with the Sidonians and Arvadians as the skilled labor force of rowers.</p>",
    "9": "<p>'The elders of Gebal and its skilled craftsmen were in you as caulkers' — Gebal is Byblos, the ancient Phoenician city (modern Jbeil, 40 km north of Beirut), one of the oldest continuously inhabited cities in the world. The Bybliotes were famous as ship-builders and repairers; the caulking of seams with tar and fiber was essential maintenance for wooden vessels. 'All the ships of the sea with their sailors were in you to trade your merchandise' — Tyre as the global emporium: all the world's ships called at Tyre.</p>",
    "10": "<p>'Persia, Lud, and Put served as soldiers in your army' — Tyre employed mercenary troops from far afield: Persia (Iran), Lud (possibly Lydia in western Anatolia or Lydians in general), and Put (Libya/Nubia). Phoenician city-states, like Greek poleis, relied heavily on mercenary soldiers rather than citizen armies. The ethnic diversity of the mercenary force reflects Tyre's commercial connections — far-flung trade relationships provided access to military specialists from across the known world.</p>",
    "11": "<p>The Arvadians and 'Gammadim' (<em>gamadim</em>, possibly mercenaries from Cilicia/southern Anatolia) manning the walls — the military defense of the island city was essential. The shields hung on the walls as decoration was a common ancient Near Eastern display of military readiness and trophies: 1 Kgs 10:16-17 describes Solomon displaying 500 large gold shields in the House of the Forest of Lebanon. 'They made your beauty perfect' — the military display as aesthetic achievement, the armed power as part of the city's magnificence.</p>",
    "12": "<p>'Tarshish was your merchant because of your abundant wealth of every kind; with silver, iron, tin, and lead they traded at your markets' — Tarshish (Spanish Tartessus, or possibly Sardinia) was Tyre's far-western trading partner for metals. The four metals listed (silver, iron, tin, lead) correspond to the metal resources of the Iberian Peninsula and Sardinian mines that ancient Phoenician colonization targeted. Tin was particularly critical: it was necessary for bronze production, and the Mediterranean world's only major tin sources in antiquity were in Spain (Rio Tinto area) and Cornwall, England.</p>",
    "13": "<p>'Javan, Tubal, and Meshech were your traders; they traded human beings and vessels of bronze in your markets' — Javan (Greece/Ionian coast), Tubal and Meshech (Asia Minor, possibly Phrygia and Cappadocia) trading slaves (<em>nephesh adam</em>, 'souls of men' — human beings as a commodity) and bronze vessels. The slave trade was a significant component of ancient Near Eastern commerce, and Phoenician merchants were prominent in it (Joel 3:6 accuses the Phoenicians of selling Israelites to the Greeks). The bronze vessels from Anatolia were famous in antiquity; Greek bronze-working tradition had deep Anatolian roots.</p>",
    "14": "<p>'From Beth-togarmah they traded horses, war horses, and mules at your markets' — Beth-Togarmah (Armenia/eastern Anatolia) as the horse-supply region. The horse trade from the north was vital for military establishments throughout the Near East; horses did not breed well in the lowlands and had to be imported from highland regions. War horses (<em>susim</em>, H5483) and 'horses of the parade/war' (<em>paras</em>, H6571, war horse/charger) were premium commodities; mules were standard pack animals and the preferred riding animals for nobility.</p>",
    "15": "<p>'The men of Dedan were your traders' — Dedan (northern Arabia, modern al-'Ula area) as a caravan hub connecting the Arabian trade to the Mediterranean via Phoenician markets. 'Many coastlands were your markets' — Tyre as the intermediary for island and coastal trade. 'They brought you tribute of ivory tusks and ebony' — ivory from African elephants (via Arabia and Egypt) and ebony (African hardwood, H1894) were luxury goods in high demand for carved furniture, inlay work, and decorative objects throughout the ancient Near East.</p>",
    "16": "<p>'Syria was your merchant because of your many products' — Syria (Aram) as a major trading partner. 'With emeralds, purple, embroidered work, fine linen, coral, and agate they traded at your markets' — the range of goods reflects Syria's position at the crossroads of Mesopotamian and Mediterranean trade. Coral (<em>ra'moth</em>, possibly red coral from the Red Sea), agate (<em>kadkod</em>, possibly crystal or carnelian) — gemstones from India and Arabia passing through Syrian middlemen.</p>",
    "17": "<p>'Judah and the land of Israel were your traders; they traded wheat from Minnith, cakes, honey, olive oil, and balm at your markets' — the specific mention of Judah/Israel as Tyre's agricultural suppliers is historically significant: the Jezreel Valley's wheat, Canaan's olive oil and honey, and the famous Gilead balm (<em>tzori</em>, the medicinal resin of the Commiphora species, cf. Gen 37:25; Jer 8:22) all flowed to Tyre's markets. Minnith (H4511, a location east of the Jordan in Ammonite territory, cf. Judg 11:33) was a wheat-producing area. This verse shows the commercial relationship that made Israel's reliance on Tyre commercially rational and spiritually dangerous.</p>",
    "18": "<p>'Damascus was your merchant for your many products because of your abundant wealth — with the wine of Helbon and white wool' — Damascus as the Aramean merchant center. Wine of Helbon (Chalybon, near Damascus): attested in cuneiform sources as a luxury wine supplied to Persian royal courts; the wine of Helbon/Aleppo region was famous throughout the ancient Near East. White wool (H6713, <em>tzemer Chaver</em>, some read 'wool of Sahar/Zahar' — a toponym) as a luxury textile raw material.</p>",
    "19": "<p>'Dan and Javan from Uzal traded at your markets; wrought iron, cassia, and fragrant calamus were among your wares' — the trade in aromatics and spices that gave Phoenician merchants their distinctive place in Mediterranean commerce. Cassia (<em>qiddah</em>, H6916, a cinnamon-related spice from South Asia or East Africa) and fragrant calamus (<em>qaneh hatov</em>, sweet cane/calamus, also from South/Southeast Asia) were luxury aromatics used in incense, medicine, and perfumery. These goods arrived via the Arabia-overland route.</p>",
    "20": "<p>'Dedan traded with you in saddlecloths for riding' — a second reference to Dedan (cf. v.15), this time specifically for riding accessories. The Arabian horse-gear trade supplemented the Armenian horse supply: horses needed saddle cloths, bridles, and tack. Arabian craftsmen were known for their leather and textile work for equestrian equipment.</p>",
    "21": "<p>'Arabia and all the princes of Kedar traded with you in lambs, rams, and goats' — the Arabian peninsula as the source of livestock for Tyre's markets. Kedar (H6938, the major confederation of north Arabian tribes mentioned in Assyrian records as <em>Qidri</em>) was the dominant pastoral power of the north Arabian steppe. The lambs and sheep supplied both wool/leather for Tyre's textile trade and animals for sacrificial use throughout the region's temples and festivals.</p>",
    "22": "<p>'The merchants of Sheba and Raamah traded with you; they traded in the finest of all spices, all kinds of precious stones, and gold' — Sheba (southwestern Arabia, possibly modern Yemen) and Raamah (unidentified, possibly in the same region) as the luxury goods suppliers from the Arabian Peninsula. The trade route from southern Arabia (the 'Incense Route') brought frankincense, myrrh, spices, and gold from Arabia and East Africa to Mediterranean ports via Tyre. This is the same commercial network referenced when the Queen of Sheba visits Solomon (1 Kgs 10:1-10).</p>",
    "23": "<p>'Haran, Canneh, Eden, the traders of Sheba, Asshur, and Chilmad were your merchants' — the northern Mesopotamian trade corridor: Haran (the major caravan city in northern Mesopotamia, also Abraham's stopping point, Gen 11:31), Canneh (possibly Calneh/Nippur in central Mesopotamia), Eden (possibly the bit-adini Aramean kingdom in the middle Euphrates region, known from Assyrian records). Asshur (Assyria) as a commercial partner even after Assyria's political fall — the infrastructure of Assyrian commerce survived the empire's collapse. This geographic sweep (from Spain/Tarshish in the west to Arabia/Sheba in the south to Mesopotamia/Asshur in the east) demonstrates Tyre's role as the commercial hub of the ancient world.</p>",
    "24": "<p>'These traded with you in choice garments, in blue and embroidered cloth, in chests of fine clothing bound with cords and made of cedar' — the luxury textile trade in which Tyre both participated and set standards. 'Blue and embroidered cloth' (<em>tekheleth</em> and <em>rikmah</em>) — the same blue-violet dye and embroidered fabric used in the tabernacle furnishings (Exod 26:1,31) points to the shared material culture of the Levantine luxury textile industry.</p>",
    "25": "<p>'The ships of Tarshish carried your merchandise; you were filled and made very glorious in the heart of the seas' — the 'ships of Tarshish' (<em>oniyot Tarshish</em>) were the largest class of Mediterranean merchant vessels, capable of the long ocean voyage to Spain. They are attested in multiple ancient sources as Phoenician/Tyrian ships. Isaiah 23:1-14 is entirely devoted to the mourning of the ships of Tarshish at Tyre's fall. The phrase 'filled and made very glorious' (<em>wattikbedi me'od belbab yamim</em>) captures the paradox of the allegory: the ship's wealth was also its fatal heaviness when the storm came.</p>",
    "26": "<p>'Your rowers have brought you out into the great waters; the east wind has wrecked you in the heart of the seas' — the east wind (<em>ruach qadim</em>, the sirocco/khamsin) coming from the Babylonian east. The nautical reversal: the same ships that carried Tyre's merchandise to the world are now wrecked. The 'heart of the seas' (<em>lev yamim</em>) is where Tyre sat in commercial glory (v.4, 25) and now where it is wrecked — the same location transforms from the center of wealth to the place of destruction.</p>",
    "27": "<p>'Your wealth, your merchandise, your goods, your mariners and pilots, your caulkers and dealers, all your men of war within you, and all your company that is in your midst will sink into the heart of the seas on the day of your fall' — the comprehensive list of everything that constituted Tyre's identity: commercial goods, the people who carried them (mariners, pilots, caulkers, traders), the military forces that defended them, all going down together. The catalog of Tyre's greatness (vv.3-25) becomes the catalog of total loss.</p>",
    "28": "<p>'At the sound of the cry of your pilots the countryside shakes' — the sound that once represented Tyre's commercial authority (the pilots giving orders) now represents their distress cry. The shaking countryside (<em>migrash</em>, H4054, open land/suburbs) reverting to shock at the maritime world's collapse. The sound that structured the commerce of the ancient Mediterranean becomes the sound of lamentation.</p>",
    "29": "<p>'All who handle the oar — the mariners and all the pilots of the sea — will come down from their ships and stand on dry land' — the reaction of the maritime world to Tyre's fall: sailors abandoning their ships, the professional mariners paralyzed with grief. The standing on dry land is a departure from their element — sailors who live at sea coming ashore in shock. The universality ('all who handle the oar') captures the scope of the commercial world's connection to Tyre.</p>",
    "30": "<p>'They will raise their voices over you and cry out bitterly; they will throw dust on their heads and roll in ashes' — the formal mourning gestures of the ancient Near East: loud crying (<em>za'aq</em>), dust-throwing on the head, rolling in ashes. These are the same mourning gestures used for personal bereavement and for the fall of cities; the commercial partners of Tyre mourn its loss as a personal bereavement because their own livelihood depended on the Tyrian commercial network.</p>",
    "31": "<p>'They will shave their heads completely for you and put on sackcloth; they will weep for you with bitter grief and bitter mourning' — the escalating mourning: shaved heads, sackcloth garments, bitter weeping. The formality of the mourning protocol indicates that the commercial partners' grief is genuine — not theatrical — because their economic existence was bound to Tyre. The fall of the commercial hub was literally catastrophic for those in its orbit.</p>",
    "32": "<p>'Who was ever destroyed like Tyre, like one silent in the midst of the sea?' — the uniqueness of Tyre's fall: there was no precedent. 'Silent in the midst of the sea' (<em>kedomah betoch hayam</em>) — the noise of Tyre's commercial activity (songs, harps, v.26:13; merchant cries, ship sounds) is replaced by silence. The sea that once rang with Tyre's commerce becomes Tyre's silent grave.</p>",
    "33": "<p>'When your merchandise went out over the seas, you satisfied many peoples; with your great wealth and goods you enriched the kings of the earth' — the tribute to Tyre's genuine commercial contribution: the city that satisfied (<em>save'at</em>) many peoples and enriched kings was not merely predatory but genuinely productive. The commercial system Tyre operated fed people, enriched regions, distributed goods. This acknowledgment of genuine benefit makes the fall more poignant and establishes that what is being mourned is a real civilizational achievement.</p>",
    "34": "<p>'Now you are wrecked by the seas, in the depths of the waters; your merchandise and all your company have sunk with you' — the completed destruction: the past tense of fulfillment. The entire commercial edifice (merchandise, company, sailors, goods) has gone down together. The depths of the water complete the image begun with Tyre 'in the heart of the seas' — the center of the world becomes the bottom of the world.</p>",
    "35": "<p>'All the inhabitants of the coastlands are appalled at you; their kings shudder with horror and their faces are troubled' — the reaction of the maritime political world to Tyre's fall. 'Appalled' (<em>shamemu</em>, H8074) and 'shudder with horror' (<em>sa'ar</em>, H8175) are the specific reactions to theophanic or catastrophic events — normally reserved for the response to YHWH's direct intervention. The fall of Tyre produces reactions appropriate to a divine act, because it is a divine act.</p>",
    "36": "<p>'The merchants among the peoples hiss at you; you have come to a horrible end and will be no more forever' — the hissing (<em>sharaq</em>, H8319, whistle/hiss) is a conventional response to destroyed cities in the OT prophetic literature (Jer 19:8; 49:17; 50:13 — all using <em>sharaq</em> for the shocked reaction to ruined cities). 'Will be no more forever' (<em>ayin ad olam</em>) — the permanent dissolution of Tyre as a distinct commercial civilization closes the dirge.</p>"
  },
  "28": {
    "1": "<p>The word-event formula introduces two closely related but distinct oracles: against the 'prince' (<em>nasi</em>) of Tyre (vv.1-10) and against the 'king' (<em>melek</em>) of Tyre (vv.11-19). The distinction between <em>nasi</em> and <em>melek</em> may reflect different aspects of the ruler's identity (his political vs. cosmic/mythological role) or may address different figures (the ruling king and an idealized/mythological Tyrian ruler).</p>",
    "2": "<p>'Say to the prince of Tyre: Because your heart is proud and you have said, I am a god; I sit in the seat of gods in the heart of the sea — but you are a man, and not a god' — Ithobaal III (c.591-573 BCE), the reigning Tyrian king during Nebuchadnezzar's siege, and the Tyrian royal ideology of divine or semi-divine status. Phoenician kings claimed the patronage and protection of Baal, Melqart (the Tyrian deity), and El; the claim to 'sit in the seat of gods' reflects this ideology. The 'seat of gods' (<em>moshav Elohim</em>) in the heart of the sea: Tyre's island location was interpreted as a quasi-divine dwelling — the sea as the realm of the divine.</p>",
    "3": "<p>'Behold, you are wiser than Daniel — no secret is hidden from you' — the reference to Daniel (<em>Dan'el</em>) is likely the same ancient figure as in 14:14: the legendary righteous and wise judge known from Ugaritic literature (the Aqhat epic, 14th-13th century BCE), where Dan'el (da-ni-il) is a righteous king renowned for judging the cause of the widow and orphan. The sarcastic comparison is rhetorically effective: the prince claims wisdom surpassing even the legendary Dan'el, but this very pride of wisdom is his indictment.</p>",
    "4": "<p>'By your wisdom and understanding you have gained wealth for yourself and accumulated gold and silver in your treasuries' — the Tyrian prince's genuine commercial wisdom is acknowledged: he did achieve extraordinary wealth through real skill. This acknowledgment makes the indictment more pointed: the pride is not delusional but based on real achievement. The conversion of genuine skill into divine self-claim is the theological problem — what begins as competence becomes arrogance when it displaces recognition of the Creator.</p>",
    "5": "<p>'By your great wisdom and in your trading you have increased your wealth, and your heart has become proud because of your wealth' — the spiritual mechanism of the fall: wisdom → trading → wealth → pride (<em>gevah lev</em>, proud heart). The Proverbs tradition consistently warns against the proud heart that results from prosperity (Prov 16:18; 18:12). The Tyrian prince's case is the paradigmatic example of this spiritual trajectory: legitimate commercial success generates illegitimate divine self-claim.</p>",
    "6": "<p>'Therefore thus says the Lord GOD: Because you have set your heart as the heart of a god' — the precise charge: not merely that he claimed divine status rhetorically, but that he mentally and functionally placed himself in the category of deity. The 'heart as a god's heart' (<em>lev levav Elohim</em>) is the interior spiritual movement that precedes the outward claim. YHWH's judgment is addressed to the interior disposition, not merely the verbal claim.</p>",
    "7": "<p>'Behold, I will bring strangers against you, the most ruthless of the nations' — the 'most ruthless of the nations' (<em>araritzei goyim</em>) is Ezekiel's recurring description of Babylon (26:7; 30:11; 31:12; 32:12). The Babylonian army as the instrument of YHWH's judgment against Tyrian hubris: the city that claimed divine status will be subjected to the most violent of human military powers. 'They will draw their swords against your beauty and wisdom' — the wisdom and beauty that constituted the divine claim will be the specific target of the sword.</p>",
    "8": "<p>'They will thrust you down into the Pit, and you will die the death of the slain in the heart of the seas' — the throne in the 'seat of the gods in the heart of the sea' (v.2) becomes the grave in the 'heart of the seas.' The spatial inversion is complete: the divine dwelling becomes the place of death. 'The Pit' (<em>shachat</em>, H7845, pit/grave/corruption) is the underworld; dying in the sea rather than in the Pit is a different kind of death — without burial, without honor, lost in the element that was the prince's source of pride.</p>",
    "9": "<p>'Will you still say, I am a god, before the one who kills you? But you will be a mere man in the hand of the one who wounds you' — the moment of the claim's falsification: death itself proves that the divine claim was false. The contrast between claiming to be a god (<em>Elohim</em>) and being 'a mere man' (<em>adam</em>) in the hand of one who wounds you is the rhetorical climax of the first oracle. Death is the universal human experience that destroys all pretensions to divinity.</p>",
    "10": "<p>'You will die the death of the uncircumcised by the hand of foreigners, for I have spoken' — the shame of dying 'the death of the uncircumcised' (<em>mot arelim</em>): in Phoenician culture, circumcision was practiced (Herodotus 2.104 notes that Phoenicians practiced circumcision along with Egyptians and Ethiopians). To die 'the death of the uncircumcised' may mean dying without the honor of proper ritual and burial, or dying as those who are outside the covenant community — the ultimate social and cultic humiliation for one who claimed divine status.</p>",
    "11": "<p>The second oracle: against the 'king' (<em>melek</em>) of Tyre, using cosmic-mythological imagery unprecedented in the OT prophetic literature. The shift from <em>nasi</em> to <em>melek</em> may signal a shift in focus: from the present historical ruler to the idealized/primordial figure behind Tyrian royal ideology. The oracle draws on motifs from the broader ancient Near Eastern mythological tradition while subverting their claims.</p>",
    "12": "<p>'You were the seal of perfection, full of wisdom and perfect in beauty' — <em>tochnit</em> (H8508, pattern/plan/seal) of perfection: the figure who is the perfect exemplar of what beauty and wisdom should be. The phrase 'full of wisdom and perfect in beauty' combines the two qualities the prince-oracle addressed — they have cosmic proportions in the king-oracle. The king of Tyre as the cosmic embodiment of the perfection that the creation intended.</p>",
    "13": "<p>'You were in Eden, the garden of God; every precious stone adorned you' — the explicit Eden location: the king of Tyre is placed in <em>Gan Eden</em> (<em>hagan-Eden</em>, the garden of God/Eden). The list of nine precious stones (ruby, topaz, diamond/crystal, beryl, onyx, jasper, sapphire, turquoise, emerald) plus gold and the crafted settings corresponds to (and partially overlaps with) the high priest's breastplate stones (Exod 28:17-20). 'On the day you were created' (<em>beyom hibbar'echa</em>) — this is a created being, not eternal: the king of Tyre/the figure behind him was created, placed in Eden, adorned with precious stones.</p>",
    "14": "<p>'You were the anointed guardian cherub (<em>cherub mimshach hasokek</em>); I had appointed you. You were on the holy mountain of God; you walked among the fiery stones' — the most theologically dense verse in the oracle. Three identifications: (1) anointed guardian cherub — a cherub given covenant anointing, placed as the guardian/covering cherub (cf. the cherubim who guard Eden in Gen 3:24); (2) on the holy mountain of God — the cosmic mountain of divine assembly (cf. Ps 48:2; Isa 14:13); (3) walking among fiery stones (<em>beevenei-esh hithhalakta</em>) — the divine throne-room phenomena of ch 1 (fiery stones in the vicinity of the chariot-throne). Whether this describes the historical Tyrian king in cosmic-mythological terms or an angelic being whose corruption underlies Tyre's spiritual reality has generated extensive theological discussion.</p>",
    "15": "<p>'You were blameless in your ways from the day you were created until iniquity was found in you' — the perfect creation narrative: created without moral flaw, the iniquity found (passive: 'was found') as something that emerged from within. The phrase parallels both the pre-fall Adam (created good) and the Serpent's corrupting influence in the garden. The transition from blameless to iniquitous is the core of the oracle and mirrors the transition in Adam/Eve narratives.</p>",
    "16": "<p>'Through the abundance of your trade you were filled inwardly with violence, and you sinned; so I cast you out as profane from the mountain of God' — the specific mechanism of the fall: commerce generating violence. <em>rechullatechu</em> (your trade/trafficking, H7404) as the source of the interior violence (<em>chamas</em>, H2555). The commercial activity that was Tyre's pride became the spiritual corrupting force. 'I cast you out as profane' (<em>chalal</em>, H2490, defiled/profaned) from the mountain of God — the expulsion from the divine mountain uses the language of ritual defilement: the sacred space cannot tolerate the profaned presence.</p>",
    "17": "<p>'Your heart was proud because of your beauty; you corrupted your wisdom for the sake of your splendor. I have cast you to the ground; I have exposed you before kings to feast their eyes on you' — the pride-fall pattern: beauty → pride → corrupted wisdom → public humiliation before kings. The 'feast their eyes on you' (<em>ra'o becha</em>) is the public spectacle of the humiliated proud: the kings of the earth watch the exposure of the one who claimed to be above them.</p>",
    "18": "<p>'By the abundance of your iniquities and the wrongdoing of your trade you defiled your sanctuaries; therefore I have brought fire from the midst of you' — the fire from within: not external destruction but internal combustion. The 'sanctuaries' (<em>miqddashecha</em>) that were defiled — the sacred spaces of Tyre, including the famous temple of Melqart described by Herodotus (2.44). 'It has consumed you' — Tyre consumed by its own internal fire, the violence that trade generated eventually destroying the trader.</p>",
    "19": "<p>'All who knew you among the peoples are appalled at you; you have become a horror and shall be no more forever' — the same closing formula as the ch 27 dirge (27:36): appalled (<em>shamemu</em>) at the one who was the seal of perfection; horror (<em>ballahot</em>); no more forever. The king-oracle closes with the same language of permanent dissolution as the ship-allegory, tying the two chapters together in a single extended meditation on Tyrian greatness and its judgment.</p>",
    "20": "<p>A brief oracle transition — the word-event formula marks the shift to the Sidon oracle. Sidon was the senior Phoenician city (Tyre was traditionally its daughter-colony) and was politically and commercially linked to Tyre throughout the period. The oracle against Sidon is much shorter than the Tyre oracles, reflecting Sidon's lesser commercial and cultic significance in Ezekiel's period.</p>",
    "21": "<p>'Son of man, set your face against Sidon and prophesy against it' — Sidon (H6721, possibly connected to 'fishing'), the city 40 km north of Tyre on the Phoenician coast. The <em>sim panim el</em> (set-face) formula is the standard opening for the OAN oracles (cf. 6:2; 13:17; 25:2; 28:2; 29:2). Sidon was involved in the anti-Babylonian coalition referenced in Jer 27:3 (Sidon sent envoys to Jerusalem along with Edom, Moab, Ammon, and Tyre to coordinate resistance to Babylon).</p>",
    "22": "<p>'Thus says the Lord GOD: Behold, I am against you, Sidon; I will be glorified in your midst. They will know that I am the LORD when I execute judgments on her and show myself holy in her' — the Sidon oracle is primarily a recognition-formula oracle. The key terms: <em>nikhbadti</em> ('I will be glorified/honored') and <em>weniqdashti</em> ('I will show myself holy') — YHWH's self-disclosure through Sidon's judgment. The oracle against Sidon is less detailed than those against Tyre because its primary purpose is to complete the Phoenician city-state section of the OAN before the Egyptian section begins.</p>",
    "23": "<p>'I will send pestilence into her and blood into her streets; the slain will fall in her midst by the sword that is against her on every side; then they will know that I am the LORD' — pestilence (<em>dever</em>) and sword as the standard dual instruments of urban judgment. The recognition formula closes the brief oracle. Sidon's historical defeat at the hands of Artaxerxes III in 345 BCE (the city was burned and 40,000 inhabitants reportedly died) is sometimes cited as a fulfillment, though the timeframe differs significantly from Ezekiel's context.</p>",
    "24": "<p>'There will no longer be a painful brier or a piercing thorn from any of the surrounding peoples who showed contempt for Israel' — the transition from judgment-oracle to restoration-promise for Israel. The 'brier and thorn' (<em>sillon mam'ir</em> and <em>qotz mak'ov</em>) language echoes Num 33:55 (the Canaanites who remain will be 'pricks in your eyes and thorns in your sides'). The judgment of Tyre, Sidon, and the other neighboring peoples eliminates the persistent hostile pressure on Israel from its commercial and political neighbors.</p>",
    "25": "<p>'Thus says the Lord GOD: When I gather the house of Israel from the peoples among whom they have been scattered, and show myself holy in them in the sight of the nations, then they will dwell in their own land that I gave to my servant Jacob' — the restoration promise that closes the entire OAN section (chs 25-28): the gathering of scattered Israel, YHWH's sanctification displayed before the nations, and the return to the Jacobite inheritance. The 'servant Jacob' (<em>avdi ya'aqov</em>) is the patriarchal ground of the land promise — the same promise that undergirds the restoration promises of chs 34-37.</p>",
    "26": "<p>'They will dwell in it safely and build houses and plant vineyards. They will live with confidence when I have executed judgments on all their neighbors who have shown contempt for them; then they will know that I am the LORD their God' — the picture of the restored Israel: security (<em>betach</em>, H983, in safety), building houses, planting vineyards — the standard covenant-blessing formula for settled abundance (Isa 65:21-22; Amos 9:14). The causal link: the security of restored Israel is contingent on the judgment of the hostile neighbors. The recognition formula here is 'I am the LORD their God' — with the possessive: after all the OAN oracles in which YHWH revealed himself to foreign nations through their judgments, he reveals himself to Israel as their specific covenant Lord.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'ezekiel')
    merge_comm(existing, EZK_CTX)
    save_comm('mkt-context', 'ezekiel', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-context/ezekiel.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/ezekiel.json').read_text())

    all_ok = True
    for ch in [26, 27, 28]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
